#!/usr/bin/perl

use strict;
use warnings;
use CGI qw(:standard);
use File::Spec;

# Configuration
my $log_dir = "/var/log/myapp";

# Get logfile parameter
my $filename = param('logfile');

# Validate and sanitize filename
if (!$filename) {
    print header();
    print "Error: No logfile specified";
    exit;
}

# Remove any directory traversal attempts
$filename =~ s/(\.\.\/|\/)/_/g;
$filename =~ s/[^a-zA-Z0-9._-]/_/g;

# Check if file exists and is within log directory
my $full_path = File::Spec->catfile($log_dir, $filename);
my $base_dir = File::Spec->rel2abs($log_dir);
my $resolved_path = File::Spec->rel2abs($full_path);

# Ensure path is within base directory
if ($resolved_path !~ /^\Q$base_dir\E/) {
    print header();
    print "Error: Invalid file path";
    exit;
}

# Check if file exists and is readable
unless (-r $full_path) {
    print header();
    print "Error: File not found or not readable";
    exit;
}

# Open and display file
open(my $fh, '<', $full_path) or die "Cannot open file: $!";
print header();
print start_html("Log Viewer");
print h1("Log File: $filename");
print "<pre>";
while (my $line = <$fh>) {
    chomp $line;
    $line =~ s/&/&amp;/g;
    $line =~ s/</&lt;/g;
    $line =~ s/>/&gt;/g;
    print "$line\n";
}
print "</pre>";
close($fh);
print end_html();